type DelegationFixture = {
  label: string;
  challenge: Uint8Array;
  delegationChainJson: string;
  validTimeNs: bigint;
  expiredTimeNs: bigint;
  iiCanisterId: string;
  userPrincipalId: string;
  /** Malformed JSON: missing `signature` on the signed delegation (parse error). */
  wrongDelegationChainJson: string;
};

const delegationFixtures: DelegationFixture[] = [
  {
    label: "legacy",
    challenge: LEGACY_CHALLENGE,
    delegationChainJson: LEGACY_DELEGATION_CHAIN_JSON,
    validTimeNs: LEGACY_EXPIRATION - BigInt(42),
    expiredTimeNs: LEGACY_EXPIRATION + BigInt(42),
    iiCanisterId: LEGACY_II_CANISTER_ID,
    userPrincipalId: LEGACY_USER_PRINCIPAL_ID,
    wrongDelegationChainJson: JSON.stringify({
      delegations: [
        {
          delegation: {
            expiration: "17b5b384762bfd21",
            pubkey: "e7875e69ce7beda6fc7b6d",
          },
        },
      ],
      publicKey: "deadbeef",
    }),
  },
  {
    label: "sig_capture",
    challenge: SIG_CAPTURE_CHALLENGE,
    delegationChainJson: SIG_CAPTURE_DELEGATION_CHAIN_JSON,
    validTimeNs: SIG_CAPTURE_CURRENT_TIME_NANOS,
    expiredTimeNs: SIG_CAPTURE_EXPIRATION + BigInt(42),
    iiCanisterId: SIG_CAPTURE_II_CANISTER_ID,
    userPrincipalId: SIG_CAPTURE_USER_PRINCIPAL_ID,
    wrongDelegationChainJson: JSON.stringify({
      delegations: [
        {
          delegation: {
            expiration: "18a3bc48afe67bc1",
            pubkey: "3059301306072a8648ce3d020106082a8648ce3d03010703420004bca93d",
          },
        },
      ],
      publicKey: "deadbeef",
    }),
  },
];

const IC_ROOT_PUBLIC_KEY_RAW = LEGACY_ROOT_PUBLIC_KEY_RAW;
const WRONG_II_CANISTER_ID = "jqajs-xiaaa-aaaad-aab5q-cai";

test.each(delegationFixtures)(
  "$label: Should validateDelegationAndGetPrincipal",
  (f) => {
    const principal = validateDelegationAndGetPrincipal(
      f.challenge,
      f.delegationChainJson,
      f.validTimeNs,
      f.iiCanisterId,
      IC_ROOT_PUBLIC_KEY_RAW,
    );
    expect(principal).toEqual(f.userPrincipalId);
  },
);

test.each(delegationFixtures)(
  "$label: Should fail validateDelegationAndGetPrincipal with wrong challenge",
  (f) => {
    const call = () =>
      validateDelegationAndGetPrincipal(
        Uint8Array.from([1, 2, 3, 5]),
        f.delegationChainJson,
        f.validTimeNs,
        f.iiCanisterId,
        IC_ROOT_PUBLIC_KEY_RAW,
      );
    expect(call).toThrow(expect.stringContaining("does not match the challenge"));
  },
);

test.each(delegationFixtures)(
  "$label: Should fail validateDelegationAndGetPrincipal with wrong delegation chain",
  (f) => {
    const call = () =>
      validateDelegationAndGetPrincipal(
        f.challenge,
        f.wrongDelegationChainJson,
        f.validTimeNs,
        f.iiCanisterId,
        IC_ROOT_PUBLIC_KEY_RAW,
      );
    expect(call).toThrow(
      expect.stringContaining("Error parsing delegation_chain"),
    );
  },
);

test.each(delegationFixtures)(
  "$label: Should fail validateDelegationAndGetPrincipal with expired delegation",
  (f) => {
    const call = () =>
      validateDelegationAndGetPrincipal(
        f.challenge,
        f.delegationChainJson,
        f.expiredTimeNs,
        f.iiCanisterId,
        IC_ROOT_PUBLIC_KEY_RAW,
      );
    expect(call).toThrow(expect.stringContaining("delegation expired"));
  },
);

test.each(delegationFixtures)(
  "$label: Should fail validateDelegationAndGetPrincipal with wrong II canister id",
  (f) => {
    const call = () =>
      validateDelegationAndGetPrincipal(
        f.challenge,
        f.delegationChainJson,
        f.validTimeNs,
        WRONG_II_CANISTER_ID,
        IC_ROOT_PUBLIC_KEY_RAW,
      );
    expect(call).toThrow(
      expect.stringContaining("does not match II canister id"),
    );
  },
);

test.each(delegationFixtures)(
  "$label: Should fail validateDelegationAndGetPrincipal with wrong IC root public key",
  (f) => {
    const badRootPk = Uint8Array.from(IC_ROOT_PUBLIC_KEY_RAW);
    badRootPk[42] += 1;
    const call = () =>
      validateDelegationAndGetPrincipal(
        f.challenge,
        f.delegationChainJson,
        f.validTimeNs,
        f.iiCanisterId,
        badRootPk,
      );
    expect(call).toThrow(
      expect.stringContaining(
        "Invalid canister signature: invalid BLS signature",
      ),
    );
  },
);
